#include<bits/stdc++.h>
using namespace std;
int main(){
	int a[101],n,c=0,d=0,e=0,f=0;
	double b;
	cin>>n;
	b=100.0/n;
	for(int i=0;i<n;i++){
		cin>>a[i];
		if(a[i]<19){
			c++;
		}else if(a[i]<36){
			d++;
		}else if(a[i]<61){
			e++;
		}else{
			f++;
		}
	}
	cout<<fixed<<setprecision(2)<<c*b<<"%"<<endl;
	cout<<fixed<<setprecision(2)<<d*b<<"%"<<endl;
	cout<<fixed<<setprecision(2)<<e*b<<"%"<<endl;
	cout<<fixed<<setprecision(2)<<f*b<<"%"<<endl;
	
}
